 using System.ComponentModel;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // ── Configuration ──────────────────────────────────────────────────────────────

 var topic = args.Length > 0
     ? string.Join(' ', args)
     : PromptForTopic();

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable.");

 var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

 Console.WriteLine($"\n🔬 Research Agent");
 Console.WriteLine($"   Topic : {topic}");
 Console.WriteLine($"   Model : {model}\n");

 // ── Tools ──────────────────────────────────────────────────────────────────────

 var notebook = new Notebook();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(
         ([Description("The search query")] string query) =>
         {
             Console.WriteLine($"  🔍 Searching: \"{query}\"");

             // Placeholder — swap in Bing Search, Google Custom Search, etc.
             return $"""
                 Search results for "{query}":
                 1. Wikipedia overview – {query} is a broad, actively-researched area …
                 2. Recent review paper – A 2025 survey highlights key advances in {query} …
                 3. Industry report – Market analysts project significant growth related to {query} …
                 (Replace with a real search API for production use.)
                 """;
         },
         name: "WebSearch",
         description: "Search the web for information on a topic. Returns relevant result snippets."),

     AIFunctionFactory.Create(
         ([Description("The note to save")] string note) =>
         {
             notebook.Add(note);
             Console.WriteLine($"  📝 Note saved  ({notebook.Count} total)");
             return $"Note saved. You now have {notebook.Count} note(s).";
         },
         name: "TakeNote",
         description: "Save a research note for later reference. Use this to record key findings."),

     AIFunctionFactory.Create(
         () =>
         {
             Console.WriteLine("  📖 Reading notes …");
             return notebook.Count == 0
                 ? "No notes yet."
                 : string.Join("\n---\n",
                       notebook.All.Select((n, i) => $"[Note {i + 1}] {n}"));
         },
         name: "ReadNotes",
         description: "Retrieve all saved research notes so you can review and synthesize them."),
 };

 // ── Agent ──────────────────────────────────────────────────────────────────────

 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(model)
     .AsIChatClient();

 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. Investigate the given topic thoroughly.

         Follow this process:
         1. Perform 2–3 web searches using different angles or sub-topics.
         2. After each search, call TakeNote to record the key findings.
         3. When you have gathered enough material, call ReadNotes to review everything.
         4. Produce a well-structured, comprehensive summary of your research.

         Be thorough but concise. Always take notes before moving to the next search.
         """,
     name: "ResearchAgent",
     description: "An agent that researches a topic using web search and note-taking.",
     tools: tools);

 Console.WriteLine("─── Agent working ───\n");

 var response = await agent.RunAsync(
     $"Research the following topic and provide a summary:\n\n{topic}",
     session: null);

 Console.WriteLine("\n═══════════════════════════════════════");
 Console.WriteLine("📋 RESEARCH SUMMARY");
 Console.WriteLine("═══════════════════════════════════════\n");
 Console.WriteLine(response.Text);
 Console.WriteLine();

 // ── Helpers ────────────────────────────────────────────────────────────────────

 static string PromptForTopic()
 {
     Console.Write("Enter a research topic: ");
     var input = Console.ReadLine()?.Trim();
     return string.IsNullOrEmpty(input) ? "the future of artificial intelligence" : input;
 }

 // ── Notebook ───────────────────────────────────────────────────────────────────

 class Notebook
 {
     private readonly List<string> _notes = [];
     public int Count => _notes.Count;
     public IReadOnlyList<string> All => _notes;
     public void Add(string note) => _notes.Add(note);
 }
